import{_ as p,o as e,c as s,ag as o}from"./chunks/framework.DtEl18Xn.js";const r="/getbiji-docs-v3/images/PVjfbK0J9ogTzmxUNrUcdHkVnNb.png",a="/getbiji-docs-v3/images/EYkvbD8vroIDfbxFs3FcnItunGh.png",n="/getbiji-docs-v3/images/KPzzbiByNoud1ixknh3c1sKFnvh.png",_="/getbiji-docs-v3/images/UUNybaHBXoIWOTxCLMfcUYG9nPb.png",h=JSON.parse('{"title":"丝滑创作小红书、小绿书爆款文案","description":"","frontmatter":{"title":"丝滑创作小红书、小绿书爆款文案","category":"最佳实践-原来还能这么用","lastUpdated":"2026-03-14T15:01:09.974Z"},"headers":[],"relativePath":"最佳实践-原来还能这么用/丝滑创作小红书小绿书爆款文案.md","filePath":"最佳实践-原来还能这么用/丝滑创作小红书小绿书爆款文案.md"}'),i={name:"最佳实践-原来还能这么用/丝滑创作小红书小绿书爆款文案.md"};function c(g,t,m,d,l,b){return e(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="丝滑创作小红书、小绿书爆款文案" tabindex="-1">丝滑创作小红书、小绿书爆款文案 <a class="header-anchor" href="#丝滑创作小红书、小绿书爆款文案" aria-label="Permalink to &quot;丝滑创作小红书、小绿书爆款文案&quot;">​</a></h1><p>公众号原文链接：<a href="https://mp.weixin.qq.com/s/1ICkJny03-VGzUgwN4wbDQ" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/1ICkJny03-VGzUgwN4wbDQ</a></p><p>原创 系统飞轮 系统飞轮 <em>2025年01月08日 19:21</em> <em>贵州</em></p><p>罗振宇跨年晚会推出Get笔记第8天，随着学习不断深入，发现了更多颇具价值运用场景。</p><p>我们先来看数据。今日罗振宇学习笔记仅新增5条，主要内容是对“新年十日谈”直播中未来5年的4大趋势进行深度解析，以及罗振宇关注的人文历史博主更新的短视频。</p><p>接下来看Get笔记使用人数情况。12点时，使用人数为303618人，较前一日20点统计时增加了5561人。据此预测，今天新增人数有望突破万人，未来几天预计新增用户也将维持在一万人左右。</p><p>今天最大的价值在于，<strong>解锁了用Get笔记完成图片加文案创作，运用于小红书、小绿书发布</strong>，图文结合效果十分完美。我们先以美食类文案为例讨论学习，后续将解锁更多运用场景。当然，更多的创意和技能有待大家进一步探索、分享。</p><p>全流程的创作步骤如下：</p><p>第一步：在百度图片中随意下载一张美食图片，保存到相册。</p><p><img src="'+r+'" alt=""></p><p>第二步：将下载的美食图片上传到Get笔记。为了让大家充分了解提示词差异，此次文案生成我未添加提示词，笔记根据既定预设要求生成文案，截屏如下：</p><p><img src="'+a+'" alt=""></p><p>倘若此时，我的角色定位<strong>为美食博主、爱做美食的妈妈等人设补充了相应提示词，<strong>按照需求可以生成推广文案了。下面这条截屏是</strong>增加了作为美食博主提示词后</strong>，生成文案可以直接发表：</p><p>再假设我的角色定位是<strong>减脂教练、正在减肥人设</strong>，对提示词进行修改。这样，Get笔记就会按照要求生成适合推广文案内容。你看，里面包含每类食物卡路里都有标明，总的卡路里也计算出来了，是不是完全满足了推广要求？而且，由于在提示词中我提出了补充明星以加强推荐效果的要求，所以在文案中把需要补充的位置预留了出来。</p><p><img src="'+n+'" alt=""></p><p>这三张图文创作时间大约为30秒，完全不受时间、工具、场地限制。也就是说**，无论何时何地，哪怕去卫生间短暂时间，都能完成创作和发布流程。**</p><p>我再分享一个创作思路。我朋友经营着一家牛肉面点店，根据他的实际情况和需求，短短几分钟便分别完成了小红书和微信两个平台的推广文案。当然，还可依据需求或场景的变化，源源不断地生成新文案。我已将这两个文案的截屏放在下方，供你对比查看。</p><p><img src="'+_+'" alt=""></p><p>当完成图文创作后，猎豹CEO傅盛所说的**“AI实则让诸多事情变得更为容易，它是不断为普通人降低门槛的工具”**这句话，给我带来了巨大的冲击。此前的两次接触，仅仅让我知晓了这一理念，而此次却让我深受触动！</p><p>试想，若你并非久经磨砺的文字高手，也未曾系统学习过产品推广运营设计，那么创作这样高质量的文案对你而言，将是难以跨越的鸿沟。然而**，随着AI的出现，只要我们有思考、有创意、有灵感，它就能帮助我们达成想要表达和创作内容，有了ai人人都可以是创作者。**</p><p>再次强调今天的学习重点**：务必认真对比不同的文案内容，如此你便能更深刻地领会Get笔记能为你带来的价值，激发更多的创作灵感。**</p><p>今日分享就到此为止，明天将继续探索。不知道你有没有发现什么不一样的亮点呢？欢迎在评论区留言交流，让我们一起探讨这款笔记的更多可能性。</p><p>以上，既然看到这里了，如果觉得不错，随手点个赞、在看、转发三连吧，如果想第一时间收到推送，也可以给我个星标⭐～谢谢你看我的文章，我们，下次再见。</p>',23)])])}const x=p(i,[["render",c]]);export{h as __pageData,x as default};
